128→const App: React.FC = () => {
129→  return <AppContent />;
130→};
131→
132→const AppContent: React.FC = () => {
133→  // ── Toast system ──
134→  const [toasts, setToasts] = useState<Toast[]>([]);
135→  const showToast = useCallback((type: Toast['type'], message: string) => {
136→    const id = Date.now().toString();
137→    setToasts(prev => [...prev, { id, type, message }]);
138→    setTimeout(() => setToasts(prev => prev.filter(t => t.id !== id)), 3500);
139→  }, []);
140→  const removeToast = useCallback((id: string) => {
141→    setToasts(prev => prev.filter(t => t.id !== id));
142→  }, []);
143→
144→  // ── 2-level routing ──
145→  const [currentView, setCurrentView] = useState<string>('home');
146→  const [activeSection, setActiveSection] = useState<string>('dashboard');
147→  const [viewHistory, setViewHistory] = useState<string[]>([]);
148→
149→  const [analysisData, setAnalysisData] = useState<AnalysisResult | null>(null);
150→  const [history, setHistory] = useState<AnalysisResult[]>([]);
151→
152→  // Load history from DB on mount
153→  useEffect(() => {
154→    const loadedHistory = db.getAll();
155→    setHistory(loadedHistory);
156→  }, []);
157→
158→  // Bibliothèques de contenu généré
159→  const [smcLibrary, setSmcLibrary] = useState<SMCContent[]>([]);
160→  const [truthLibrary, setTruthLibrary] = useState<SMCContent[]>([]);
161→  const [schemaLibrary, setSchemaLibrary] = useState<SMCContent[]>([]);
162→  const [robotsLibrary, setRobotsLibrary] = useState<SMCContent[]>([]);
163→
164→  const [megaStatus, setMegaStatus] = useState<MegaGenerationStatus>('idle');
165→  const [isAnalyzing, setIsAnalyzing] = useState(false);
166→  const [resultsTab, setResultsTab] = useState<'overview' | 'details' | 'archives' | 'recommendations'>('overview');
167→  const [publisherRequestData, setPublisherRequestData] = useState<{ topic: string, url: string, brief: string } | null>(null);
168→  const [initialRechargePackId, setInitialRechargePackId] = useState<number | null>(null);
169→  const [initialAccountTab, setInitialAccountTab] = useState<'profile' | 'subscription' | 'billing'>('profile');
170→
171→  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
172→
173→  // Command Palette (Ctrl+K) & Keyboard Shortcuts (?)
174→  const [isCommandPaletteOpen, setIsCommandPaletteOpen] = useState(false);
175→  const [isShortcutsOpen, setIsShortcutsOpen] = useState(false);
176→  const [lowCreditsDismissed, setLowCreditsDismissed] = useState(false);
177→  useEffect(() => {
178→    const handleKeyDown = (e: KeyboardEvent) => {
179→      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
180→        e.preventDefault();
181→        setIsCommandPaletteOpen(prev => !prev);
182→      }
183→      if (e.key === 'Escape') {
184→        setIsCommandPaletteOpen(false);
185→        setIsShortcutsOpen(false);
186→      }
187→      if (e.key === '?' && !(e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement)) {
188→        setIsShortcutsOpen(prev => !prev);
189→      }
190→    };
191→    document.addEventListener('keydown', handleKeyDown);
192→    return () => document.removeEventListener('keydown', handleKeyDown);
193→  }, []);
194→
195→  // ── Welcome Onboarding Modal ──
196→  const [showOnboarding, setShowOnboarding] = useState(false);
197→
198→  // Default user is NULL to allow testing the login flow
199→  const [user, setUser] = useState<User | null>(null);
200→  const animatedCredits = useAnimatedNumber(user?.credits ?? 0);
201→  const [showCelebration, setShowCelebration] = useState(false);
202→
203→  // Show onboarding modal on first login
204→  useEffect(() => {
205→    if (user && !localStorage.getItem('citedby_onboarded')) {
206→      setShowOnboarding(true);
207→    }
208→  }, [user]);
209→
210→  // Calcul du nombre de projets consommé sur le mois en cours (Renouvellement mensuel)
211→  const monthlyProjectCount = useMemo(() => {
212→    if (history.length === 0) return 0;
213→
214→    const now = new Date();
215→    const billingCycleStart = new Date(now.getFullYear(), now.getMonth(), 1);
216→
217→    const projectCreationDates = new Map<string, Date>();
218→
219→    history.forEach(h => {
220→        let hostname;
221→        try { hostname = new URL(h.url).hostname; } catch(e) { hostname = h.url; }
222→
223→        const analysisDate = new Date(h.timestamp);
224→
225→        if (!projectCreationDates.has(hostname)) {
226→            projectCreationDates.set(hostname, analysisDate);
227→        } else {
228→            if (analysisDate < projectCreationDates.get(hostname)!) {
229→                projectCreationDates.set(hostname, analysisDate);
230→            }
231→        }
232→    });
233→
234→    let count = 0;
235→    projectCreationDates.forEach((creationDate) => {
236→        if (creationDate >= billingCycleStart) {
237→            count++;
238→        }
239→    });
240→
241→    return count;
242→  }, [history]);
243→
244→  // Vérifier si le plan d'action est complet
245→  const actionPlanStatus = useMemo(() => {
246→    if (history.length === 0) return { complete: false, completed: 0, total: 0 };
247→    const latest = history[history.length - 1];
248→    const total = latest.recommendations.length;
249→    const completed = latest.recommendations.filter(rec =>
250→      latest.generatedSolutions?.[rec.id]
251→    ).length;
252→    return { complete: total > 0 && completed === total, completed, total };
253→  }, [history]);
254→
255→  // ── Navigation (stable callbacks — no re-render cascade) ──
256→  const navigateTo = useCallback((view: string) => {
257→    setIsMobileMenuOpen(false);
258→    if (view !== 'recharge') setInitialRechargePackId(null);
259→    if (view !== 'account') setInitialAccountTab('profile');
260→    setCurrentView(prev => {
261→      setViewHistory(h => [...h, prev]);
262→      return view;
263→    });
264→    const section = PAGE_TO_SECTION[view];
265→    if (section) setActiveSection(section);
266→  }, []);
267→
268→  const handleSectionChange = useCallback((section: string) => {
269→    const firstPage = FIRST_PAGE_PER_SECTION[section] || section;
270→    navigateTo(firstPage);
271→  }, [navigateTo]);
272→
273→  const handlePageChange = useCallback((page: string) => {
274→    navigateTo(page);
275→  }, [navigateTo]);
276→
277→  const goBack = useCallback(() => {
278→    setIsMobileMenuOpen(false);
279→    setViewHistory(prev => {
280→      if (prev.length > 0) {
281→        const newHistory = [...prev];
282→        const prevView = newHistory.pop();
283→        if (prevView) setCurrentView(prevView);
284→        return newHistory;
285→      }
286→      setCurrentView('home');
287→      return [];
288→    });
289→  }, []);
290→
291→  const handleDirectRecharge = useCallback((packId: number) => {
292→    setInitialRechargePackId(packId);
293→    navigateTo('recharge');
294→  }, [navigateTo]);
295→
296→  const handleAnalyze = async (url: string) => {
297→    if (user) {
298→        const limit = PLAN_LIMITS[user.plan] || 1;
299→        let hostname = url;
300→        try { hostname = new URL(url).hostname; } catch(e) {}
301→
302→        const isExistingProject = history.some(h => {
303→            try { return new URL(h.url).hostname === hostname; }
304→            catch(e) { return false; }
305→        });
306→
307→        if (!isExistingProject && monthlyProjectCount >= limit) {
308→            alert(`Limite de nouveaux projets atteinte pour ce mois (${monthlyProjectCount}/${limit}). Passez au plan supérieur pour ajouter plus de projets.`);
309→            setInitialAccountTab('subscription');
310→            navigateTo('account');
311→            return;
312→        }
313→    }
314→
315→    setIsAnalyzing(true);
316→    try {
317→      const result = await analyzeUrl(url);
318→      setAnalysisData(result);
319→
320→      const updatedHistory = db.add(result);
321→      setHistory(updatedHistory);
322→
323→      if (history.length === 0) {
324→        setShowCelebration(true);
325→        setTimeout(() => setShowCelebration(false), 3000);
326→      }
327→
328→      showToast('success', 'Audit terminé avec succès !');
329→
330→      setMegaStatus('generating');
331→      megaGenerate(url).then(cache => {
332→        if (cache) {
333→          const preGenerated = { status: 'completed' as const, generatedAt: new Date().toISOString(), ...cache };
334→          setHistory(prev => {
335→            if (prev.length === 0) return prev;
336→            const updated = { ...prev[0], preGenerated };
337→            db.update(0, updated);
338→            return [updated, ...prev.slice(1)];
339→          });
340→          setAnalysisData(prev => prev ? { ...prev, preGenerated } : prev);
341→          setMegaStatus('completed');
342→        } else {
343→          setMegaStatus('failed');
344→        }
345→      }).catch(() => setMegaStatus('failed'));
346→
347→      setResultsTab('details');
348→      navigateTo('projects');
349→    } catch (error) {
350→      console.error("Analysis failed", error);
351→      alert("Erreur lors de l'analyse. Veuillez réessayer.");
352→    } finally {
353→      setIsAnalyzing(false);
354→    }
355→  };
356→
357→  const handleViewAnalysis = (result: AnalysisResult, tab: any = 'overview') => {
358→    setAnalysisData(result);
359→    setResultsTab(tab);
360→    navigateTo('projects');
361→  };
362→
363→  const handleViewDirectoryEntity = (result: AnalysisResult) => {
364→    setAnalysisData(result);
365→    navigateTo('directory-entity');
366→  };
367→
368→  const handleUpdateAnalysis = (index: number, updatedData: Partial<AnalysisResult>) => {
369→    const updatedHistory = db.update(index, updatedData);
370→    setHistory(updatedHistory);
371→  };
372→
373→  const handleSaveSolution = useCallback((analysisId: string, recommendationId: string, solution: GeneratedSolution) => {
374→    const timestamp = new Date().toISOString();
375→    const solutionWithMeta = { ...solution, timestamp };
376→
377→    setAnalysisData(prev => {
378→        if (!prev || prev.timestamp !== analysisId) return prev;
379→        return {
380→            ...prev,
381→            generatedSolutions: {
382→                ...(prev.generatedSolutions || {}),
383→                [recommendationId]: solutionWithMeta
384→            }
385→        };
386→    });
387→
388→    setHistory(prevHistory => {
389→        const index = prevHistory.findIndex(item => item.timestamp === analysisId);
390→        if (index !== -1) {
391→            const updatedItem = {
392→                ...prevHistory[index],
393→                generatedSolutions: {
394→                    ...(prevHistory[index].generatedSolutions || {}),
395→                    [recommendationId]: solutionWithMeta
396→                }
397→            };
398→            const newHistory = [...prevHistory];
399→            newHistory[index] = updatedItem;
400→            db.update(index, updatedItem);
401→            return newHistory;
402→        }
403→        return prevHistory;
404→    });
405→  }, []);
406→
407→  const handleAddToSmcLibrary = useCallback((item: SMCContent) => setSmcLibrary(prev => [item, ...prev]), []);
408→  const handleAddToTruthLibrary = useCallback((item: SMCContent) => setTruthLibrary(prev => [item, ...prev]), []);
409→  const handleAddToSchemaLibrary = useCallback((item: SMCContent) => setSchemaLibrary(prev => [item, ...prev]), []);
410→  const handleAddToRobotsLibrary = useCallback((item: SMCContent) => setRobotsLibrary(prev => [item, ...prev]), []);
411→
412→  const handleNavigateToPublisher = useCallback((data: { topic: string, url: string, brief: string }) => {
413→    setPublisherRequestData(data);
414→    navigateTo('publisher-request');
415→  }, [navigateTo]);
416→
417→  const handleNavigateToDirectory = useCallback(() => {
418→    navigateTo('directory');
419→  }, [navigateTo]);
420→
421→  const handleDeductCredits = (amount: number): boolean => {
422→    if (!user) {
423→        if(confirm("Vous devez être connecté pour effectuer cette action. Se connecter maintenant ?")) {
424→            navigateTo('login');
425→        }
426→        return false;
427→    }
428→
429→    if (user.credits < amount) {
430→        alert(`Solde GTO Gas insuffisant pour générer cette solution.\n\nIl vous manque ${amount - user.credits} crédits.\n\nRedirection vers la station de recharge...`);
431→        navigateTo('recharge');
432→        return false;
433→    }
434→
435→    setUser(prev => prev ? { ...prev, credits: prev.credits - amount } : null);
436→    return true;
437→  };
438→
439→  const handleRecharge = (amount: number, planLevel: 'free' | 'pro' | 'enterprise') => {
440→    if (!user) return;
441→    setUser({
442→        ...user,
443→        credits: user.credits + amount,
444→        plan: planLevel
445→    });
446→  };
447→
448→  const handleUpgradePlan = (newPlan: 'free' | 'pro' | 'enterprise') => {
449→    if (!user) return;
450→    setUser({ ...user, plan: newPlan });
451→  };
452→
453→  const handleLogin = useCallback((loggedInUser: User) => {
454→    setUser(loggedInUser);
455→    setViewHistory(['home']);
456→    setCurrentView('dashboard');
457→    setActiveSection('dashboard');
458→  }, []);
459→
460→  const handleLogout = useCallback(() => {
461→    setIsMobileMenuOpen(false);
462→    setUser(null);
463→    setCurrentView('home');
464→    setActiveSection('dashboard');
465→    setViewHistory([]);
466→  }, []);
467→
468→  useEffect(() => {
469→    if (!user && isMobileMenuOpen) {
470→      setIsMobileMenuOpen(false);
471→    }
472→  }, [user, isMobileMenuOpen]);
473→
474→  // ── Render page content ──
475→  const renderPage = () => {
476→    switch (currentView) {
477→      case 'home':
478→        return <Home onNavigate={navigateTo} user={user} onDirectRecharge={handleDirectRecharge} />;
479→      case 'login':
480→        return <Login onLogin={handleLogin} onBack={goBack} />;
481→      case 'dashboard':
482→        return <Dashboard onBack={goBack} history={history} onView={handleViewAnalysis} onNavigate={navigateTo} />;
483→      case 'new-analysis':
484→      case 'analyze':
485→        return <Analyze onAnalyze={handleAnalyze} isAnalyzing={isAnalyzing} />;
486→      case 'generative-tools':
487→        return <GenerativeTools onNavigate={navigateTo} history={history} megaStatus={megaStatus} />;
488→      case 'results':
489→      case 'audit-aeo':
490→        return analysisData ? <Results data={analysisData} onBack={goBack} user={user} onDeductCredits={handleDeductCredits} onSaveSolution={handleSaveSolution} initialTab={resultsTab as any} onNewAnalysis={() => navigateTo('new-analysis')} /> : null;
491→      case 'action-plan':
492→      case 'projects':
493→      case 'rescan':
494→        return <Projects onBack={goBack} onNavigateToAnalysis={() => navigateTo('new-analysis')} user={user} history={history} onViewAnalysis={handleViewAnalysis} projectCount={monthlyProjectCount} maxProjects={user ? PLAN_LIMITS[user.plan] : 1} onNavigateToPlan={() => { setInitialAccountTab('subscription'); navigateTo('account'); }} onDeductCredits={handleDeductCredits} onSaveSolution={handleSaveSolution} onNewAnalysis={() => navigateTo('new-analysis')} onNavigateToRecharge={() => navigateTo('credits')} initialUrl={analysisData?.url} initialTab={resultsTab} />;
495→      case 'history':
496→        return <HistoryView onBack={goBack} history={history} onView={handleViewAnalysis} />;
497→      case 'citation-dashboard':
498→      case 'ai-monitoring':
499→        return <AiMonitoring onBack={goBack} onNavigate={navigateTo} onDeductCredits={handleDeductCredits} user={user} />;
500→      case 'tracked-queries':
501→      case 'benchmark':
502→      case 'monthly-report':
503→        return <PlaceholderPage title={currentView === 'tracked-queries' ? 'Requêtes cibles' : currentView === 'benchmark' ? 'Benchmark' : 'Rapports mensuels'} />;
504→      case 'multilingual':
505→        return <MultilingualCitations onBack={goBack} user={user} onDeductCredits={handleDeductCredits} />;
506→      case 'alerts':
507→      case 'alerts-aeo':
508→        return <AlertsAEO onBack={goBack} user={user} onNavigate={navigateTo} />;
509→      case 'smc-studio':
510→        return <SMCStudio onBack={goBack} user={user} onDeductCredits={handleDeductCredits} library={smcLibrary} onAddToLibrary={handleAddToSmcLibrary} onNavigateToPublisher={handleNavigateToPublisher} onNavigateToDirectory={handleNavigateToDirectory} />;
511→      case 'blog-optimizer':
512→        return <BlogOptimizer onBack={goBack} user={user} onDeductCredits={handleDeductCredits} onNavigateToPublisher={handleNavigateToPublisher} />;
513→      case 'schema-org':
514→        return <SchemaOrg onBack={goBack} history={history} user={user} onDeductCredits={handleDeductCredits} savedFiles={schemaLibrary} onSaveFile={handleAddToSchemaLibrary} />;
515→      case 'robots-txt':
516→        return <RobotsTxt onBack={goBack} history={history} user={user} onDeductCredits={handleDeductCredits} onUpdateAnalysis={handleUpdateAnalysis} savedFiles={robotsLibrary} onSaveFile={handleAddToRobotsLibrary} />;
517→      case 'source-of-truth':
518→        return <SourceOfTruth onBack={goBack} history={history} user={user} onDeductCredits={handleDeductCredits} savedFiles={truthLibrary} onSaveFile={handleAddToTruthLibrary} />;
519→      case 'llms-txt':
520→        return <LlmsTxtGenerator onBack={goBack} user={user} onDeductCredits={handleDeductCredits} history={history} />;
521→      case 'content-writer':
522→        return <ContentWriter onBack={goBack} user={user} onDeductCredits={handleDeductCredits} />;
523→      case 'ai-response-layer':
524→        return <AiResponseLayer onBack={goBack} user={user} onDeductCredits={handleDeductCredits} />;
525→      case 'answer-first':
526→      case 'answer-first-audit':
527→        return <AnswerFirstAudit onBack={goBack} user={user} onDeductCredits={handleDeductCredits} history={history} />;
528→      case 'ai-citation-simulator':
529→        return <AiCitationSimulator onBack={goBack} user={user} onDeductCredits={handleDeductCredits} />;
530→      case 'eeat-builder':
531→        return <EeatBuilder onBack={goBack} user={user} onDeductCredits={handleDeductCredits} history={history} />;
532→      case 'reputation':
533→        return <Reputation onBack={goBack} user={user} onDeductCredits={handleDeductCredits} />;
534→      case 'bot-tracking':
535→        return <BotTracking onBack={goBack} user={user} />;
536→      case 'publisher-search':
537→      case 'publisher-request':
538→        return <PublisherRequest onBack={goBack} user={user} data={publisherRequestData} />;
539→      case 'my-orders':
540→      case 'publisher-dashboard':
541→        return <PlaceholderPage title={currentView === 'my-orders' ? 'Mes commandes' : 'Espace publisher'} />;
542→      case 'directory':
543→        return <Directory onBack={goBack} onViewEntity={handleViewDirectoryEntity} onNavigateToPlan={() => { setInitialAccountTab('subscription'); navigateTo('account'); }} user={user} directClientCount={monthlyProjectCount} maxClients={user ? PLAN_LIMITS[user.plan] : 1} actionPlanComplete={actionPlanStatus.complete} actionPlanProgress={actionPlanStatus} onNavigateToActionPlan={() => { setResultsTab('recommendations'); navigateTo('projects'); }} />;
544→      case 'directory-entity':
545→        return analysisData ? <DirectoryEntity data={analysisData} onBack={goBack} /> : null;
546→      case 'profile':
547→      case 'subscription':
548→      case 'account':
549→        return <Account user={user} onLogout={handleLogout} onNavigate={navigateTo} onUpgrade={handleUpgradePlan} projectCount={monthlyProjectCount} maxProjects={user ? PLAN_LIMITS[user.plan] : 1} initialTab={currentView === 'subscription' ? 'subscription' : initialAccountTab} />;
550→      case 'plan':
551→        return <Plan onBack={goBack} user={user} onUpgrade={handleUpgradePlan} />;
552→      case 'credits':
553→      case 'recharge':
554→        return <Recharge onBack={goBack} onRecharge={handleRecharge} user={user} onNavigate={navigateTo} initialPackId={initialRechargePackId} />;
555→      case 'invoices':
556→        return <PlaceholderPage title="Facturation" />;
557→      case 'api-keys':
558→      case 'api-developer':
559→        return <ApiDeveloper onBack={goBack} user={user} onDeductCredits={handleDeductCredits} />;
560→      case 'affiliation':
561→        return <Affiliation onBack={goBack} user={user} />;
562→      case 'integrations':
563→        return <Integrations onBack={goBack} user={user} onDeductCredits={handleDeductCredits} />;
564→      case 'analytics-integrations':
565→        return <AnalyticsIntegrations onBack={goBack} user={user} />;
566→      case 'clients':
567→        return <Clients onBack={goBack} onNavigate={navigateTo} user={user} directClientCount={monthlyProjectCount} maxClients={user ? PLAN_LIMITS[user.plan] : 1} />;
568→      case 'mission-orders':
569→        return <MissionOrders onBack={goBack} user={user} onNavigate={navigateTo} />;
570→      case 'messages':
571→        return <Messages onBack={goBack} user={user} />;
572→      default:
573→        return <PlaceholderPage title="Page introuvable" />;
574→    }
575→  };
576→
577→  // Public pages (no AppShell)
578→  const isPublicPage = ['home', 'login'].includes(currentView);
579→
580→  return (
581→    <ToastContext.Provider value={{ showToast }}>
582→    <div className="min-h-screen font-sans text-gray-100 selection:bg-primary/30">
583→      {/* Toast Notifications */}
584→      <ToastContainer toasts={toasts} onRemove={removeToast} />
585→
586→      {/* First Audit Celebration */}
587→      {showCelebration && (
588→        <div className="fixed inset-0 z-[200] pointer-events-none flex items-center justify-center">
589→          <div className="text-center animate-in fade-in zoom-in duration-500">
590→            <div className="text-6xl mb-4 animate-bounce">🎉</div>
591→            <div className="bg-[#13131d]/90 backdrop-blur-xl border border-purple-500/30 rounded-2xl px-8 py-5 shadow-2xl shadow-purple-900/30">
592→              <h3 className="text-xl font-bold text-white mb-1">Premier audit réussi !</h3>
593→              <p className="text-sm text-purple-300">Votre parcours AEO commence maintenant</p>
594→            </div>
595→          </div>
596→          {Array.from({ length: 20 }).map((_, i) => (
597→            <div
598→              key={i}
599→              className="absolute w-2 h-2 rounded-full"
600→              style={{
601→                background: ['#a855f7', '#8b5cf6', '#f59e0b', '#10b981', '#ec4899'][i % 5],
602→                left: `${20 + Math.random() * 60}%`,
603→                top: `${20 + Math.random() * 60}%`,
604→                animation: `fade-in 0.3s ease-out ${i * 50}ms both, slide-in-from-bottom 1.5s ease-out ${i * 50}ms both`,
605→                opacity: 0,
606→              }}
607→            />
608→          ))}
609→        </div>
610→      )}
611→
612→      {/* Welcome Onboarding Modal */}
613→      <OnboardingModal
614→        show={showOnboarding}
615→        onClose={() => setShowOnboarding(false)}
616→        onNavigate={(view: string) => navigateTo(view)}
617→      />
618→
619→      {/* Command Palette (Ctrl+K) */}
620→      {user && isCommandPaletteOpen && (
621→        <div className="fixed inset-0 z-[100] flex items-start justify-center pt-[20vh]" onClick={() => setIsCommandPaletteOpen(false)}>
622→          <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" />
623→          <CommandPalettePanel
624→            onClose={() => setIsCommandPaletteOpen(false)}
625→            onNavigate={(view: string) => { navigateTo(view); setIsCommandPaletteOpen(false); }}
626→          />
627→        </div>
628→      )}
629→
630→      {/* Keyboard Shortcuts Modal (?) */}
631→      <ShortcutsModal isOpen={isShortcutsOpen} onClose={() => setIsShortcutsOpen(false)} />
632→
633→      {/* Content */}
634→      {isPublicPage ? (
635→        // Public pages — raw, no AppShell
636→        <div className="bg-black min-h-screen">
637→          <Suspense fallback={<div className="min-h-screen bg-black" />}>
638→            {renderPage()}
639→          </Suspense>
640→        </div>
641→      ) : (
642→        // Authenticated pages — wrapped in AppShell
643→        <AppShell
644→          activeSection={activeSection}
645→          onSectionChange={handleSectionChange}
646→          activePage={currentView}
647→          onPageChange={handlePageChange}
648→          credits={animatedCredits}
