650→          user={user ? { name: user.name, email: user.email } : null}
651→          onOpenCommandPalette={() => setIsCommandPaletteOpen(true)}
652→          onLogoClick={() => navigateTo('dashboard')}
653→        >
654→          {/* Low Credits Warning Banner */}
655→          {user && user.credits <= 10 && !lowCreditsDismissed && currentView !== 'credits' && currentView !== 'recharge' && (
656→            <div className="mb-4 px-4 py-2.5 rounded-xl bg-amber-500/10 border border-amber-500/20 flex items-center gap-3">
657→              <AlertTriangle size={16} className="text-amber-400 shrink-0" />
658→              <p className="text-sm text-amber-300 flex-1">Crédits bientôt épuisés ({user.credits} restants). <button onClick={() => navigateTo('credits')} className="underline font-semibold hover:text-amber-200">Recharger maintenant</button></p>
659→              <button onClick={() => setLowCreditsDismissed(true)} className="text-amber-400/60 hover:text-amber-300"><X size={14} /></button>
660→            </div>
