662→
663→          <Suspense fallback={
664→            <div className="space-y-6">
665→              <div className="flex items-center justify-between">
666→                <div className="h-8 w-48 skeleton-shimmer rounded-xl" />
667→                <div className="h-10 w-36 skeleton-shimmer rounded-full" />
668→              </div>
669→              <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
670→                {[1,2,3,4].map(i => <div key={i} className="h-28 skeleton-shimmer rounded-2xl border border-white/[0.04]" />)}
671→              </div>
672→              <div className="h-64 skeleton-shimmer rounded-2xl border border-white/[0.04]" />
673→            </div>
674→          }>
675→            <div key={currentView} className="flex-1 flex flex-col animate-in fade-in slide-in-from-bottom-2 duration-300">
676→              {renderPage()}
677→            </div>
678→          </Suspense>
679→
680→          {/* Floating Action Button — New Audit */}
681→          {user && (
682→            <button
683→              onClick={() => navigateTo('new-analysis')}
684→              className="fixed bottom-8 right-6 z-40 w-14 h-14 rounded-full bg-gradient-to-br from-blue-500 to-purple-600 shadow-xl shadow-blue-900/40 flex items-center justify-center text-white hover:scale-110 hover:shadow-2xl transition-all duration-300 group"
685→              title="Nouvel Audit AEO"
686→            >
687→              <Plus size={24} className="group-hover:rotate-90 transition-transform duration-300" />
688→            </button>
