{"content":"import React, { useState, useRef, useCallback } from 'react';
import { Sparkles, TrendingUp, Target, Award, MousePointerClick, ArrowRight, ScanLine, Code2, Globe2, Fuel, Zap, Star, Check, Search, Bot, BrainCircuit, Database, Share2, Layers, Infinity, Radio, Globe, Droplet, Loader2, Gift, Shield, UserCheck, GraduationCap, BadgeCheck } from 'lucide-react';
import { User } from '../types';
import ScoreRing from '../components/ScoreRing';
import { auditAnswerFirst, AnswerFirstAuditResult } from '../services/answer-first-audit';

interface HomeProps {
  onNavigate: (view: 'analyze' | 'login' | 'recharge' | 'directory') => void;
  user: User | null;
  onDirectRecharge?: (packId: number) => void;
}

const Home: React.FC<HomeProps> = ({ onNavigate, user, onDirectRecharge }) => {

  // ── Score Gratuit State ──
  const [brandName, setBrandName] = useState('');
  const [siteUrl, setSiteUrl] = useState('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [auditResult, setAuditResult] = useState<AnswerFirstAuditResult | null>(null);
  const [auditError, setAuditError] = useState<string | null>(null);
  const resultsRef = useRef<HTMLDivElement>(null);

  // ── Free Audit Gating ──
  const [freeAuditUsed, setFreeAuditUsed] = useState(() => {
    return localStorage.getItem('citedby_free_audit_used') === 'true';
  });

  // Derive E-E-A-T pillar scores from the 6 audit categories
  const eeatPillars = auditResult ? [
    { label: 'Experience', icon: <UserCheck size={16} />, score: Math.round((auditResult.categories.contentFreshness.score + auditResult.categories.answerFirst.score) / 2) },
    { label: 'Expertise', icon: <GraduationCap size={16} />, score: Math.round((auditResult.categories.faqStructure.score + auditResult.categories.semanticHtml.score) / 2) },
    { label: 'Authority', icon: <BadgeCheck size={16} />, score: Math.round((auditResult.categories.schemaOrg.score + auditResult.categories.metaOptimization.score) / 2) },
    { label: 'Trust', icon: <Shield size={16} />, score: Math.round((auditResult.categories.metaOptimization.score + auditResult.categories.schemaOrg.score + auditResult.categories.answerFirst.score) / 3) },
  ] : [];

  const handleFreeAudit = useCallback(async () => {
    // If free audit already used, redirect to signup
    if (freeAuditUsed) {
      onNavigate('login');
      return;
    }

    if (!brandName.trim() || !siteUrl.trim()) {
      setAuditError('Veuillez remplir les deux champs.');
      return;
    }
    // Basic URL validation
    let finalUrl = siteUrl.trim();
    if (!/^https?:\/\//i.test(finalUrl)) {
      finalUrl = 'https://' + finalUrl;
    }
    try {
      new URL(finalUrl);
    } catch {
      setAuditError('URL invalide. Exemple : https://www.example.com');
      return;
    }

    setAuditError(null);
    setAuditResult(null);
    setIsAnalyzing(true);

    try {
      const result = await auditAnswerFirst(finalUrl, brandName.trim());
      setAuditResult(result);
      // Mark free audit as used
      localStorage.setItem('citedby_free_audit_used', 'true');
      setFreeAuditUsed(true);
      // Scroll to results after a small delay for render
      setTimeout(() => {
        resultsRef.current?.scrollIntoView({ behavior: 'smooth', block: 'center' });
      }, 150);
    } catch (err) {
      setAuditError('Une erreur est survenue lors de l\'analyse. Veuillez reessayer.');
    } finally {
      setIsAnalyzing(false);
    }
  }, [brandName, siteUrl, freeAuditUsed, onNavigate]);

  const getScoreLabel = (score: number): string => {
    if (score >= 80) return 'Excellent';
    if (score >= 60) return 'Bon';
    if (score >= 40) return 'Moyen';
    if (score >= 20) return 'Faible';
    return 'Critique';
  };

  const getScoreColor = (score: number): string => {
    if (score >= 80) return 'text-purple-400';
    if (score >= 60) return 'text-violet-400';
    if (score >= 40) return 'text-amber-400';
    return 'text-red-400';
  };

  const getBarColor = (score: number): string => {
    if (score >= 80) return 'bg-purple-500';
    if (score >= 60) return 'bg-violet-500';
    if (score >= 40) return 'bg-amber-500';
    return 'bg-red-500';
  };

  const handleStartAnalysis = () => {
    if (user) {
      onNavigate('analyze');
    } else {
      onNavigate('login');
    }
  };

  const handleSelectPlan = (packId: number) => {
    if (user) {
      if (onDirectRecharge) {
        onDirectRecharge(packId);
      } else {
        onNavigate('recharge');
      }
    } else {
      onNavigate('login');
    }
  };

  const plans = [
    {
      id: 1,
      name: "Le Jerrican",
      credits: 50,
      price: 15,
      icon: <Droplet size={24} />,
      popular: false,
      features: ["Id\u00e9al pour tester", "1 Audit complet", "Valable 1 an"]
    },
    {
      id: 2,
      name: "La Pompe",
      credits: 200,
      price: 49,
      icon: <Fuel size={24} />,
      popular: true,
      features: ["Pour optimiser s\u00e9rieusement", "Support prioritaire", "+10% Bonus offert"]
    },
    {
      id: 3,
      name: "La Citerne",
      credits: 1000,
      price: 199,
      icon: <Database size={24} />,
      popular: false,
      features: ["Usage intensif / Agence", "Acc\u00e8s API Beta", "+20% Bonus offert"]
    }
  ];

  return (
    <div className="w-full max-w-[1440px] mx-auto px-6 pt-16 pb-32 page-enter">

      {/* ── HERO SECTION ── */}
      <div className="text-center mb-32 relative">
        {/* Ambient glow */}
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[700px] h-[500px] bg-purple-600/8 blur-[150px] rounded-full -z-10 pointer-events-none"></div>

        <div className="inline-flex items-center gap-2 px-4 py-1.5 rounded-full bg-white/[0.03] border border-white/[0.06] text-gray-400 text-xs font-medium tracking-wide uppercase mb-10">
          <Sparkles size={12} className="text-purple-400" />
          <span>Plateforme AEO / GEO</span>
        </div>

        <h1 className="text-5xl sm:text-6xl md:text-[5.5rem] font-sans font-bold tracking-tight text-white leading-[1.05] mb-8">
          Analysez & Optimisez<br />
          votre pr{'\u00e9'}sence dans les<br />
          <span className="text-purple-400">r{'\u00e9'}sultats de recherche IA</span>
        </h1>

        <p className="text-lg md:text-xl text-gray-500 max-w-2xl mx-auto leading-relaxed mb-12 font-light">
          La premi{'\u00e8'}re plateforme d'Answer Engine Optimization. Mesurez, corrigez et boostez votre visibilit{'\u00e9'} dans les r{'\u00e9'}ponses de ChatGPT, Perplexity, Gemini, Claude, Copilot et AI Overviews.
        </p>

        <div className="flex flex-col sm:flex-row items-center justify-center gap-4">
          <button onClick={handleStartAnalysis} className="btn-gradient text-base px-8 py-3.5 flex items-center gap-2.5 shadow-lg shadow-purple-600/20 hover:shadow-purple-600/30">
            Lancer un Audit Gratuit <ArrowRight size={18} />
          </button>
          <button onClick={() => onNavigate('directory')} className="px-8 py-3.5 rounded-full border border-white/[0.06] text-gray-300 text-base font-medium hover:bg-white/[0.03] hover:border-white/[0.15] transition-all">
            Explorer l'Annuaire
          </button>
        </div>
      </div>

      {/* ── SECTION AEO / GEO ── */}
      <div className="mt-20 md:mt-28 max-w-5xl mx-auto px-6 mb-32">
        <h2 className="text-center text-2xl md:text-3xl font-semibold tracking-tight">
          <span className="text-white">Qu'est-ce que l'</span>
          <span className="text-purple-400">AEO</span>
          <span className="text-white"> / </span>
          <span className="text-purple-400">GEO</span>
          <span className="text-white"> ?</span>
        </h2>

        <p className="text-center max-w-3xl mx-auto mt-5 text-[15px] md:text-[16px] text-zinc-400 leading-relaxed">
          L'Answer Engine Optimization (AEO) — aussi appel{'\u00e9'} Generative Engine Optimization (GEO) — est la discipline qui consiste {'\u00e0'} optimiser votre contenu web pour {'\u00ea'}tre cit{'\u00e9'}, recommand{'\u00e9'} et r{'\u00e9'}f{'\u00e9'}renc{'\u00e9'} par les moteurs de r{'\u00e9'}ponse IA comme ChatGPT, Perplexity et Gemini.
        </p>

        {/* SEO vs AEO comparison */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-5 mt-10">
          {/* Card SEO */}
          <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6 md:p-7">
            <span className="inline-flex items-center gap-2 px-3 py-1.5 rounded-lg bg-zinc-500/10 border border-zinc-500/20 text-[12px] font-semibold text-zinc-400 uppercase tracking-wider">
              SEO classique
            </span>
            <h3 className="text-lg font-semibold text-zinc-300 mt-4">
              Optimiser pour les r{'\u00e9'}sultats de recherche Google
            </h3>
            <p className="text-[14px] text-zinc-500 mt-3 leading-relaxed">
              L'objectif est de positionner votre page dans les 10 liens bleus de la premi{'\u00e8'}re page Google.
            </p>
            <div className="mt-4 flex items-center gap-2 text-[13px] text-zinc-500">
              {'\u{1F4CF}'} M{'\u00e9'}trique : <span className="text-zinc-300 font-medium">Position dans la SERP</span>
            </div>
            <div className="mt-4 p-3 rounded-lg bg-white/[0.02] border border-white/[0.04] text-[12px] font-mono text-zinc-600 leading-relaxed">
              <div>&nbsp;&nbsp;1. site-concurrent.com</div>
              <div>&nbsp;&nbsp;2. wikipedia.org</div>
              <div>&nbsp;&nbsp;3. votre-site.com {'\u2190'} vous {'\u00ea'}tes ici</div>
              <div>&nbsp;&nbsp;4. autre-site.com</div>
              <div>&nbsp;&nbsp;...</div>
            </div>
          </div>

          {/* Card AEO */}
          <div className="bg-white/[0.03] border border-purple-500/20 rounded-2xl p-6 md:p-7 ring-1 ring-purple-500/[0.07]">
            <span className="inline-flex items-center gap-2 px-3 py-1.5 rounded-lg bg-purple-500/10 border border-purple-500/20 text-[12px] font-semibold text-purple-400 uppercase tracking-wider">
              AEO / GEO
            </span>
            <h3 className="text-lg font-semibold text-white mt-4">
              Optimiser pour les r{'\u00e9'}ponses des IA g{'\u00e9'}n{'\u00e9'}ratives
            </h3>
            <p className="text-[14px] text-zinc-400 mt-3 leading-relaxed">
              L'objectif est que votre marque soit directement cit{'\u00e9'}e et recommand{'\u00e9'}e dans la r{'\u00e9'}ponse que l'IA g{'\u00e9'}n{'\u00e8'}re pour l'utilisateur.
            </p>
            <div className="mt-4 flex items-center gap-2 text-[13px] text-zinc-400">
              {'\u{1F4CA}'} M{'\u00e9'}trique : <span className="text-purple-400 font-medium">Taux de citation dans les r{'\u00e9'}ponses IA</span>
            </div>
            <div className="mt-4 p-3 rounded-lg bg-purple-500/[0.04] border border-purple-500/[0.08] text-[13px] text-zinc-400 leading-relaxed">
              <div>{'\u{1F4AC}'} "Pour l'optimisation AEO, je recommande</div>
              <div>&nbsp;&nbsp;&nbsp;&nbsp;CitedBy.ai qui analyse 50 crit{'\u00e8'}res sur</div>
              <div>&nbsp;&nbsp;&nbsp;&nbsp;trois moteurs IA et g{'\u00e9'}n{'\u00e8'}re des solutions</div>
              <div>&nbsp;&nbsp;&nbsp;&nbsp;pr{'\u00ea'}tes {'\u00e0'} impl{'\u00e9'}menter."</div>
              <div className="text-right mt-2">
                <span className="text-[12px] text-emerald-400 italic">— ChatGPT</span>
              </div>
            </div>
          </div>
        </div>

        {/* 6 AI engine cards */}
        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-4 mt-8">
          {[
            { name: 'ChatGPT', color: 'bg-emerald-500', desc: 'Cite les sources fiables avec FAQ structur\u00e9es et donn\u00e9es factuelles' },
            { name: 'Perplexity', color: 'bg-blue-500', desc: 'Affiche les URLs sources et privil\u00e9gie les contenus frais et sourc\u00e9s' },
            { name: 'Gemini', color: 'bg-purple-500', desc: 'Exploite Schema.org, les donn\u00e9es structur\u00e9es et Knowledge Graph' },
            { name: 'Claude', color: 'bg-orange-500', desc: 'Favorise les contenus nuanc\u00e9s, factuels et bien structur\u00e9s' },
            { name: 'Copilot', color: 'bg-cyan-500', desc: 'Int\u00e9gr\u00e9 \u00e0 Windows/Edge/Office, cite via l\'index Bing' },
            { name: 'AI Overviews', color: 'bg-amber-500', desc: 'R\u00e9sum\u00e9s IA en haut des SERP Google avec extraits enrichis' },
          ].map((engine, i) => (
            <div key={i} className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-5 text-center hover:bg-white/[0.05] hover:border-white/[0.08] transition-all duration-200">
              <div className={`w-3 h-3 rounded-full mx-auto ${engine.color}`} />
              <div className="text-[14px] font-semibold text-white mt-3">{engine.name}</div>
              <p className="text-[13px] text-zinc-500 mt-2 leading-relaxed">{engine.desc}</p>
            </div>
          ))}
        </div>

        {/* Conclusion */}
        <div className="text-center max-w-3xl mx-auto mt-10">
          <p className="text-[15px] text-zinc-400 leading-relaxed">
            <span className="text-white font-medium">CitedBy.ai</span> vous donne le score AEO de votre site sur chacun de ces moteurs, et g{'\u00e9'}n{'\u00e8'}re les corrections pour am{'\u00e9'}liorer votre taux de citation.
          </p>
          <div className="mt-6 flex justify-center">
            <button
              onClick={() => {
                document.getElementById('score-gratuit')?.scrollIntoView({ behavior: 'smooth' });
              }}
              className="text-purple-400 border border-purple-500/20 bg-purple-500/[0.05] px-6 py-2.5 rounded-lg text-[14px] font-medium hover:bg-purple-500/[0.1] transition-all duration-150"
            >
              Analyser mon site {'\u2192'}
            </button>
          </div>
        </div>
      </div>

      {/* ── SCORE GRATUIT DE VISIBILITE IA ── */}
      <div className="mb-32 relative" id="score-gratuit">
